function validateQuery(parsed) {
  const ALLOWED_TABLES = ['Leads', 'Reports'];
  if (!parsed || typeof parsed !== 'object') return 'Generated query is not a valid object.';
  if (!ALLOWED_TABLES.includes(parsed.table)) return 'Generated query references a disallowed table.';
  if (parsed.filterByFormula && typeof parsed.filterByFormula !== 'string') return 'filterByFormula must be a string.';
  const forbidden = ['failures', 'delete(', 'update(', 'insert(', 'drop('];
  const lower = (parsed.filterByFormula || '').toLowerCase();
  if (forbidden.some((k) => lower.includes(k))) return 'Generated query contains a disallowed operation.';
  if (parsed.maxRecords !== undefined && (typeof parsed.maxRecords !== 'number' || parsed.maxRecords <= 0)) return 'maxRecords must be a positive number.';
  return null;
}

export const code = async (inputs) => {
  const question = inputs.question || '';
  const apiKey = 'YOUR_OPENAI_API_KEY_HERE';

  const SCHEMA_CONTEXT = `
Tables you may query (read-only), Airtable REST semantics — no joins, no SQL:

Leads (fields): Email, Full Name, Company, Phone, Source, Created At, Duplicate, Lead Score,
  ICP Tier, Industry, Company Size, Country, Territory, Assigned Rep, AI Reasoning,
  Priority, Deal Value, Assigned CSM, Onboarding Completed At, Status

Reports (fields): Week Start, Week End, Leads Count, MQLs Count, SQLs Count,
  Conversion Rate, Revenue, Lost Deals, AI Summary, Created At

Rules:
- Only ever query one table: Leads or Reports.
- Return ONLY JSON, no markdown fences, no explanation:
  {"table": "Leads"|"Reports", "filterByFormula": "<Airtable formula string, or empty string for no filter>", "maxRecords": <integer, max 200>}
`;

  let raw;
  try {
    const response = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${apiKey}` },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        messages: [
          { role: 'system', content: `You translate questions into Airtable read queries.\n${SCHEMA_CONTEXT}` },
          { role: 'user', content: question },
        ],
        temperature: 0.1,
      }),
    });
    if (!response.ok) {
      const err = new Error(`OpenAI request failed: ${response.status}`);
      err.status = response.status;
      throw err;
    }
    const data = await response.json();
    raw = data.choices?.[0]?.message?.content?.trim() ?? '';
  } catch (err) {
    return { parsedQuery: null, rejected: true, rejectionReason: `AI provider unavailable (${err.message})` };
  }

  const cleaned = raw.replace(/```json|```/g, '').trim();
  let parsed;
  try {
    parsed = JSON.parse(cleaned);
  } catch (e) {
    return { parsedQuery: null, rejected: true, rejectionReason: 'Model did not return valid JSON.' };
  }

  const rejection = validateQuery(parsed);
  if (rejection) {
    return { parsedQuery: null, rejected: true, rejectionReason: rejection };
  }

  return {
    parsedQuery: {
      table: parsed.table,
      filterByFormula: parsed.filterByFormula || '',
      maxRecords: Math.min(parsed.maxRecords || 50, 200),
    },
    rejected: false,
    rejectionReason: null,
  };
};

export const code = async (inputs) => {
  const apiKey = 'YOUR_OPENAI_API_KEY_HERE';
  const question = inputs.question || '';
  let records = [];
  try {
    const parsed = typeof inputs.resultBody === 'string' ? JSON.parse(inputs.resultBody) : inputs.resultBody;
    records = parsed?.records || [];
  } catch (e) {
    records = [];
  }

  if (!records.length) {
    return { answer: "I ran the query but got no matching results — try rephrasing or widening the timeframe." };
  }

  const rows = records.map((r) => r.fields);

  try {
    const response = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${apiKey}` },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        messages: [
          { role: 'system', content: 'You explain query results in one short, plain-English paragraph. Only use the data given, never invent numbers.' },
          { role: 'user', content: `Question: ${question}\n\nResult rows (JSON): ${JSON.stringify(rows).slice(0, 4000)}` },
        ],
        temperature: 0.1,
      }),
    });
    if (!response.ok) {
      const err = new Error(`OpenAI request failed: ${response.status}`);
      err.status = response.status;
      throw err;
    }
    const data = await response.json();
    const answer = data.choices?.[0]?.message?.content?.trim() ?? '';
    return { answer };
  } catch (err) {
    return { answer: `I found ${rows.length} matching record(s), but couldn't generate a plain-English summary right now (AI provider unavailable: ${err.message}).` };
  }
};

